const body = $input.first().json.body ?? $input.first().json;
const { sequence_id, step_id, patient_id, doctor_id, scheduled_date, duration_minutes, notes, google_calendar_id } = body;

if (!sequence_id) throw new Error('sequence_id is required');
if (!step_id) throw new Error('step_id is required');
if (!patient_id) throw new Error('patient_id is required');
if (!doctor_id) throw new Error('doctor_id is required');
if (!scheduled_date) throw new Error('scheduled_date is required');
if (!duration_minutes || duration_minutes < 1) throw new Error('duration_minutes must be > 0');

return [{ json: { sequence_id, step_id, patient_id, doctor_id, scheduled_date, duration_minutes: parseInt(duration_minutes, 10), notes: notes || null, google_calendar_id: google_calendar_id || null } }];

const rows = $input.all();
if (rows.length === 0) throw new Error('Step not found');
const step = rows[0].json;
if (step.appointment_id) throw new Error('Step already has an appointment');

const parse = $('Parse Input').first().json;
const { scheduled_date, duration_minutes, doctor_id, patient_id, notes, google_calendar_id, sequence_id } = parse;

// Build appointment datetime strings
const startDt = `${scheduled_date}T09:00:00`;
const endDt   = (() => {
  const d = new Date(`${scheduled_date}T09:00:00`);
  d.setMinutes(d.getMinutes() + duration_minutes);
  return d.toISOString().slice(0, 19);
})();

const summary = `${step.service_name} - Paso ${step.step_number}: ${step.step_name}`;

// Look up calendar_source_id
const calendarSourceSQL = google_calendar_id
  ? `SELECT id AS calendar_source_id FROM calendar_sources WHERE google_calendar_id = '${google_calendar_id}' LIMIT 1`
  : `SELECT NULL::bigint AS calendar_source_id`;

return [{ json: {
  ...parse,
  step_number: step.step_number,
  step_name: step.step_name,
  summary,
  startDt,
  endDt,
  calendarSourceSQL,
} }];

const calRow = $input.all()[0]?.json;
const calSourceId = calRow?.calendar_source_id || null;
const build = $('Build Appointment Data').first().json;

const insertApptSQL = `
  INSERT INTO appointments (
    patient_id, assignee_id, start_datetime, end_datetime,
    summary, notes, status, sequence_id, step_position, milestone_status, calendar_source_id
  ) VALUES (
    '${build.patient_id}',
    '${build.doctor_id}',
    '${build.startDt}',
    '${build.endDt}',
    '${build.summary.replace(/'/g, "''")}',
    ${build.notes ? `'${build.notes.replace(/'/g, "''")}'` : 'NULL'},
    'scheduled',
    '${build.sequence_id}',
    ${build.step_number},
    'waiting',
    ${calSourceId ? calSourceId : 'NULL'}
  )
  RETURNING id;
`;

const updateStepSQL = `
  UPDATE treatment_steps
  SET
    appointment_id = (${insertApptSQL.replace('RETURNING id;', 'RETURNING id').trim()}),
    scheduled_date = '${build.scheduled_date}',
    status = 'scheduled',
    updated_at = NOW()
  WHERE id = '${build.step_id}'
  RETURNING id, sequence_id, step_number, step_name, scheduled_date::text, duration_minutes, status, notes, appointment_id, completed_at::text;
`;

// Simpler: run insert then update in two queries
return [{ json: { ...build, calSourceId, insertApptSQL } }];

const apptRow = $input.all()[0]?.json;
const apptId = apptRow?.id;
if (!apptId) throw new Error('Failed to create appointment');

const build = $('Build Appointment Data').first().json;

return [{ json: { step_id: build.step_id, appointment_id: apptId, scheduled_date: build.scheduled_date } }];

const rows = $input.all();
const r = rows[0].json;
return [{ json: {
  success: true,
  appointment_id: r.appointment_id,
  step: {
    id: r.id,
    sequence_id: r.sequence_id,
    step_number: r.step_number,
    step_name: r.step_name,
    scheduled_date: r.scheduled_date || null,
    duration_minutes: r.duration_minutes,
    status: r.status,
    notes: r.notes || null,
    appointment_id: r.appointment_id,
    completed_at: r.completed_at || null,
  },
} }];
